export function getRandomReason(category?: Category): NoReason {
  const pool = category ? reasons.filter(r => r.category === category) : reasons;
  return pool[Math.floor(Math.random() * pool.length)];
}

export function getReasonById(id: number): NoReason | undefined {
  return reasons.find(r => r.id === id);
}

export function getReasonsByCategory(category: Category): NoReason[] {
  return reasons.filter(r => r.category === category);
}
